import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
const supabase = createClient(supabaseUrl, supabaseServiceKey);

// --- Упрощённый расчёт плановой даты ---
function calculatePlan(op: any) {
    const today = new Date();
        today.setHours(0, 0, 0, 0);

            let recDate = new Date(8640000000000000);
                if (op.interval_months) {
                        recDate = op.last_date ? new Date(op.last_date) : new Date(today);
                                recDate.setMonth(recDate.getMonth() + op.interval_months);
                                    }

                                        let recMileage = op.last_mileage ? op.last_mileage + (op.interval_km || 0) : (op.interval_km || 0);
                                            const avgDailyMileage = 30;
                                                const avgDailyMotohours = 1.5;

                                                    let dateByMileage = new Date(8640000000000000);
                                                        if (recMileage > (op.current_mileage || 0) && avgDailyMileage > 0) {
                                                                const days = Math.ceil((recMileage - (op.current_mileage || 0)) / avgDailyMileage);
                                                                        dateByMileage = new Date(today);
                                                                                dateByMileage.setDate(today.getDate() + days);
                                                                                    }

                                                                                        let dateByMoto = new Date(8640000000000000);
                                                                                            if (op.interval_motohours && avgDailyMotohours > 0) {
                                                                                                    const recMotohours = op.last_motohours ? op.last_motohours + op.interval_motohours : op.interval_motohours;
                                                                                                            if (recMotohours > (op.current_motohours || 0)) {
                                                                                                                        const daysMoto = Math.ceil((recMotohours - (op.current_motohours || 0)) / avgDailyMotohours);
                                                                                                                                    dateByMoto = new Date(today);
                                                                                                                                                dateByMoto.setDate(today.getDate() + daysMoto);
                                                                                                                                                        }
                                                                                                                                                            }

                                                                                                                                                                const planDate = new Date(Math.min(recDate.getTime(), dateByMileage.getTime(), dateByMoto.getTime()));
                                                                                                                                                                    const daysLeft = Math.ceil((planDate.getTime() - today.getTime()) / 86400000);
                                                                                                                                                                        return { daysLeft, planDate: planDate.toISOString().split("T")[0] };
                                                                                                                                                                        }

                                                                                                                                                                        // --- Отправка push через FCM API v1 ---
                                                                                                                                                                        async function sendFCM(playerId: string, message: string) {
                                                                                                                                                                            const accessToken = await getAccessToken();
                                                                                                                                                                                const fcmUrl = `https://fcm.googleapis.com/v1/projects/car-k3eper/messages:send`;
                                                                                                                                                                                    const res = await fetch(fcmUrl, {
                                                                                                                                                                                            method: "POST",
                                                                                                                                                                                                    headers: {
                                                                                                                                                                                                                "Authorization": `Bearer ${accessToken}`,
                                                                                                                                                                                                                            "Content-Type": "application/json",
                                                                                                                                                                                                                                    },
                                                                                                                                                                                                                                            body: JSON.stringify({
                                                                                                                                                                                                                                                        message: {
                                                                                                                                                                                                                                                                        token: playerId,
                                                                                                                                                                                                                                                                                        notification: {
                                                                                                                                                                                                                                                                                                            title: "Напоминание о ТО",
                                                                                                                                                                                                                                                                                                                                body: message,
                                                                                                                                                                                                                                                                                                                                                },
                                                                                                                                                                                                                                                                                                                                                                webpush: {
                                                                                                                                                                                                                                                                                                                                                                                    notification: {
                                                                                                                                                                                                                                                                                                                                                                                                            icon: "icon-192.png",
                                                                                                                                                                                                                                                                                                                                                                                                                                    click_action: "http://localhost:8000/?tab=to", // замените на свой реальный домен
                                                                                                                                                                                                                                                                                                                                                                                                                                                        },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    console.log("FCM response:", await res.text());
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // --- Получение OAuth2-токена ---
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    async function getAccessToken() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const raw = Deno.env.get("FIREBASE_SERVICE_ACCOUNT_JSON") || "{}";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const SERVICE_ACCOUNT = JSON.parse(raw);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (!SERVICE_ACCOUNT.client_email) throw new Error("Service account JSON not configured");

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const now = Math.floor(Date.now() / 1000);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const header = { alg: "RS256", typ: "JWT" };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const claim = {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    iss: SERVICE_ACCOUNT.client_email,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            scope: "https://www.googleapis.com/auth/firebase.messaging",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    aud: "https://oauth2.googleapis.com/token",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            exp: now + 3600,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    iat: now,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const encoder = new TextEncoder();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const key = await crypto.subtle.importKey(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        "pkcs8",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                pemToArrayBuffer(SERVICE_ACCOUNT.private_key),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        { name: "RSASSA-PKCS1-v1_5", hash: "SHA-256" },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ["sign"]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const jwt = btoa(JSON.stringify(header)) + "." + btoa(JSON.stringify(claim));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const signature = await crypto.subtle.sign("RSASSA-PKCS1-v1_5", key, encoder.encode(jwt));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const signedJwt = jwt + "." + b64urlEncode(new Uint8Array(signature));

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const res = await fetch("https://oauth2.googleapis.com/token", {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    method: "POST",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            headers: { "Content-Type": "application/x-www-form-urlencoded" },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    body: `grant_type=urn:ietf:params:oauth:grant-type:jwt-bearer&assertion=${signedJwt}`,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const data = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                return data.access_token;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                function pemToArrayBuffer(pem: string) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const b64 = pem.replace(/-----.*?-----/g, "").replace(/\s/g, "");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const binary = atob(b64);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const bytes = new Uint8Array(binary.length);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return bytes.buffer;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    function b64urlEncode(buffer: Uint8Array) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return btoa(String.fromCharCode(...buffer))
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .replace(/\+/g, "-")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        .replace(/\//g, "_")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .replace(/=+$/, "");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // --- Основной обработчик ---
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                serve(async (_req: Request) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // Получаем всех подписчиков
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const { data: subscriptions, error: subError } = await supabase
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .from("push_subscriptions")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .select("user_id, player_id");

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    if (subError) throw subError;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (!subscriptions || subscriptions.length === 0) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return new Response(JSON.stringify({ status: "ok", subscriptions: 0 }), {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        status: 200,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        headers: { "Content-Type": "application/json" },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    for (const sub of subscriptions) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // Ищем автомобили, к которым пользователь имеет доступ (владелец или со-владелец)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const { data: cars } = await supabase
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .from("cars")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .select("id")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .or(`user_id.eq.${sub.user_id},id.in.(select car_id from car_shares where invited_user_id=eq.${sub.user_id} and accepted=eq.true)`);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (!cars || cars.length === 0) continue;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    for (const car of cars) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const { data: operations } = await supabase
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        .from("operations")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .select("*")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .eq("car_id", car.id);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (!operations) continue;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const actions7: string[] = [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const actions2: string[] = [];

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                for (const op of operations) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const plan = calculatePlan(op);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (plan.daysLeft === 7) actions7.push(op.name);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            else if (plan.daysLeft === 2) actions2.push(op.name);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            let pushMessage = "";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const reminderText = "\n🛒 Не забудь про запчасти, список в приложении";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (actions7.length > 0) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                pushMessage = "🔔 Через 7 дней: " + actions7.join(", ") + reminderText;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } else if (actions2.length > 0) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    pushMessage = "⏰ Через 2 дня: " + actions2.join(", ") + reminderText;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    if (pushMessage) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        await sendFCM(sub.player_id, pushMessage);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return new Response(JSON.stringify({ status: "ok" }), {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                status: 200,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            headers: { "Content-Type": "application/json" },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                console.error(error);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return new Response(JSON.stringify({ error: error.message }), {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    status: 500,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                headers: { "Content-Type": "application/json" },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });